return msg;

// Randomise state for a new Q-learning training episode.
var levels = [25, 75, 150, 500];
var sunshine = [0, 100, 400, 900];
var temps = [16.0, 19.0, 22.0, 26.0];
flow.set('Z1Level', levels[Math.floor(Math.random() * levels.length)]);
flow.set('Z2Level', levels[Math.floor(Math.random() * levels.length)]);
flow.set('Z1Light',  Math.random() < 0.5);
flow.set('Z2Light',  Math.random() < 0.5);
flow.set('Z1Blinds', Math.random() < 0.5);
flow.set('Z2Blinds', Math.random() < 0.5);
flow.set('Spotlight', Math.random() < 0.3);
flow.set('Z1Radiator', Math.random() < 0.5);
flow.set('Z2Radiator', Math.random() < 0.5);
flow.set('Z1Temp', temps[Math.floor(Math.random() * temps.length)]);
flow.set('Z2Temp', temps[Math.floor(Math.random() * temps.length)]);
flow.set('Sunshine', sunshine[Math.floor(Math.random() * sunshine.length)]);
flow.set('SunshinePinned', false);
flow.set('EnergyCost', 0);
msg.payload = { reset: true };
return msg;

// Pin simulator to an exact deterministic state for benchmarking.
// Accepts JSON body with any subset of: Z1Level, Z2Level, Z1Light,
// Z2Light, Z1Blinds, Z2Blinds, Spotlight, Sunshine.
// When Sunshine is supplied, SunshinePinned is raised so the periodic
// update_env function will NOT randomise it away on the next tick.
// Always resets energy counters so each benchmark scenario starts fresh.
var p = msg.payload;
if (p.Z1Level   !== undefined) flow.set('Z1Level',   p.Z1Level);
if (p.Z2Level   !== undefined) flow.set('Z2Level',   p.Z2Level);
if (p.Z1Light   !== undefined) flow.set('Z1Light',   p.Z1Light);
if (p.Z2Light   !== undefined) flow.set('Z2Light',   p.Z2Light);
if (p.Z1Blinds  !== undefined) flow.set('Z1Blinds',  p.Z1Blinds);
if (p.Z2Blinds  !== undefined) flow.set('Z2Blinds',  p.Z2Blinds);
if (p.Spotlight !== undefined) flow.set('Spotlight', p.Spotlight);
if (p.Sunshine  !== undefined) { flow.set('Sunshine', p.Sunshine); flow.set('SunshinePinned', true); }
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
msg.payload = { status: 'ok' };
return msg;

var z1level = 0;
var z2level = 0;
var energy = flow.get("TotalEnergyCost");

var sun = flow.get('Sunshine');
var hr = flow.get('Hour');
if (hr >= 24) hr = 0;
flow.set('Hour', hr + 0.1);

// Sunshine hovers around 150 lux unless explicitly pinned via setState
// (benchmark scenarios pin Sunshine to make results reproducible).
if (!flow.get('SunshinePinned')) {
    flow.set("Sunshine", 150 + 50 * Math.random());
    sun = flow.get('Sunshine');
}

// ── Illuminance contributions ──────────────────────────────────────
// Ceiling light Z1: primary +400 lux to Z1, bleed +50 lux to Z2
z1level += flow.get('Z1Light') ? 400 : 0;
z2level += flow.get('Z1Light') ?  50 : 0;

// Ceiling light Z2: primary +300 lux to Z2, bleed +50 lux to Z1
z1level += flow.get('Z2Light') ?  50 : 0;
z2level += flow.get('Z2Light') ? 300 : 0;

// Blind Z1: sun * 0.5 to Z1, sun * 0.25 bleed to Z2
z1level += flow.get('Z1Blinds') ? sun * 0.50 : 0;
z2level += flow.get('Z1Blinds') ? sun * 0.25 : 0;

// Blind Z2: sun * 0.5 to Z2, sun * 0.25 bleed to Z1
z1level += flow.get('Z2Blinds') ? sun * 0.25 : 0;
z2level += flow.get('Z2Blinds') ? sun * 0.50 : 0;

// Spotlight: shared +250 lux equally to BOTH zones
var spot = flow.get('Spotlight') ? 250 : 0;
z1level += spot;
z2level += spot;

// ── Energy (per tick) ─────────────────────────────────────────────
// Ceiling lights: 1 unit/tick each
energy += flow.get('Z1Light') ? 1 : 0;
energy += flow.get('Z2Light') ? 1 : 0;
// Spotlight: 3 units/tick (high energy cost)
energy += flow.get('Spotlight') ? 3 : 0;
// Radiators: 1 unit/tick each
energy += flow.get('Z1Radiator') ? 1 : 0;
energy += flow.get('Z2Radiator') ? 1 : 0;

// ── Temperature simulation ─────────────────────────────────────────
var z1temp = flow.get('Z1Temp');
var z2temp = flow.get('Z2Temp');
z1temp += flow.get('Z1Radiator') ?  0.5 : -0.05;
z2temp += flow.get('Z2Radiator') ?  0.5 : -0.05;
z1temp = Math.min(35, Math.max(15, z1temp));
z2temp = Math.min(35, Math.max(15, z2temp));
flow.set('Z1Temp', z1temp);
flow.set('Z2Temp', z2temp);

flow.set('Z1Level', z1level);
flow.set('Z2Level', z2level);
flow.set("TotalEnergyCost", energy);

return msg;
